   116→ *
   117→ *  @return EINVAL if cache is NULL, 0 otherwise
   118→ */
   119→int
   120→cache_clear(struct cache *cache, ev_tstamp age)
   121→{
   122→    struct cache_entry *entry, *tmp;
   123→
   124→    if (!cache) {
   125→        return EINVAL;
   126→    }
   127→
   128→    ev_tstamp now = ev_time();
   129→
   130→    HASH_ITER(hh, cache->entries, entry, tmp){
   131→        if (now - entry->ts > age) {
   132→            HASH_DEL(cache->entries, entry);
   133→            if (entry->data != NULL) {
   134→                if (cache->free_cb) {
   135→                    cache->free_cb(entry->key, entry->data);
   136→                } else {
   137→                    ss_free(entry->data);
   138→                }
   139→            }
   140→            ss_free(entry->key);
   141→            ss_free(entry);
   142→        }
   143→    }
   144→
   145→    return 0;
   146→}
   147→
   148→/** Removes a cache entry
   149→ *
   150→ *  @param cache
   151→ *  The cache object
   152→ *
   153→ *  @param key
   154→ *  The key of the entry to remove
   155→ *
   156→ *  @param key_len
   157→ *  The length of key
   158→ *
   159→ *  @return EINVAL if cache is NULL, 0 otherwise
   160→ */
